window.HK2_LC9 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["He is lifting a vase off the floor.", "He is shaping a piece of pottery.", "He is setting bowls onto a shelf.", "He is wiping off his hands."], "optko": ["그는 바닥에서 꽃병을 들어 올리고 있다.", "그는 도자기 한 점을 빚고 있다.", "그는 그릇들을 선반에 놓고 있다.", "그는 손을 닦고 있다."], "ans": 1, "audio": "Test09_01.mp3", "img": "hk2_t9_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["They are preparing a meal.", "They are rinsing some plates.", "They are serving food to some guests.", "They are facing each other."], "optko": ["그들은 식사를 준비하고 있다.", "그들은 접시들을 헹구고 있다.", "그들은 손님들에게 음식을 내고 있다.", "그들은 서로를 마주 보고 있다."], "ans": 0, "audio": "Test09_02.mp3", "img": "hk2_t9_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["She is picking up a backpack.", "She is looking into a mirror.", "She is packing items into a suitcase.", "She is grasping on to a handle."], "optko": ["그녀는 배낭을 집어 올리고 있다.", "그녀는 거울을 보고 있다.", "그녀는 여행 가방에 물건들을 싸고 있다.", "그녀는 손잡이를 움켜잡고 있다."], "ans": 3, "audio": "Test09_03.mp3", "img": "hk2_t9_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["People are working on a platform.", "Some windows are being shut.", "Workers are climbing a ladder.", "Some machinery is being repaired."], "optko": ["사람들이 단 위에서 작업하고 있다.", "창문들이 닫히고 있다.", "작업자들이 사다리를 오르고 있다.", "기계가 수리되고 있다."], "ans": 0, "audio": "Test09_04.mp3", "img": "hk2_t9_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["A woman is swinging a club.", "An athlete is hanging a flagpole.", "A woman is squatting down on the grass.", "Some sporting equipment is being piled in a field."], "optko": ["한 여자가 골프채를 휘두르고 있다.", "운동선수가 깃대를 걸고 있다.", "한 여자가 잔디 위에 웅크리고 앉아 있다.", "운동 기구들이 들판에 쌓이고 있다."], "ans": 2, "audio": "Test09_05.mp3", "img": "hk2_t9_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["A sofa has been covered with a blanket.", "Chairs have been arranged on a patio.", "A glass door leads to an outdoor pool.", "A picture is mounted on the wall."], "optko": ["소파가 담요로 덮여 있다.", "의자들이 안마당에 정리되어 있다.", "유리문이 야외 수영장으로 통한다.", "그림이 벽에 고정되어 있다."], "ans": 3, "audio": "Test09_06.mp3", "img": "hk2_t9_q6.jpg"}, {"n": 7, "part": 2, "q": "Who proofread these documents?", "qko": "누가 이 문서들을 교정했나요?", "opts": ["The copy editor.", "Some customer surveys.", "Mr. Kinsley can come."], "optko": ["원고 편집자요.", "고객 설문 조사요.", "Mr. Kinsley는 올 수 있어요."], "ans": 0, "audio": "Test09_07.mp3"}, {"n": 8, "part": 2, "q": "Why is the company hiring more employees?", "qko": "회사는 왜 직원들을 더 고용하고 있나요?", "opts": ["I'll accompany you.", "The personnel department.", "There are many upcoming projects."], "optko": ["제가 당신과 함께 갈게요.", "인사부요.", "다가오는 프로젝트들이 많아요."], "ans": 2, "audio": "Test09_08.mp3"}, {"n": 9, "part": 2, "q": "Where did you get your hair cut?", "qko": "머리를 어디에서 잘랐나요?", "opts": ["It really suits you.", "Just a short trim, please.", "At the place on State Street."], "optko": ["그것이 당신에게 정말 잘 어울려요.", "그냥 짧게 다듬어 주세요.", "State가에 있는 곳에서요."], "ans": 2, "audio": "Test09_09.mp3"}, {"n": 10, "part": 2, "q": "Can't the deadline be extended by a day?", "qko": "마감 기한이 하루 연장될 수 없나요?", "opts": ["Decreased enrollment.", "Unfortunately not.", "Last Monday."], "optko": ["줄어든 등록자 수요.", "유감스럽게도 안 돼요.", "지난 월요일이요."], "ans": 1, "audio": "Test09_10.mp3"}, {"n": 11, "part": 2, "q": "My furniture was delivered this morning.", "qko": "오늘 아침에 제 가구가 배달되었어요.", "opts": ["What did you order?", "For my redecorated bedroom.", "They will be shipped soon."], "optko": ["무엇을 주문했나요?", "새롭게 장식된 제 침실을 위해서요.", "그것들은 곧 운송될 거예요."], "ans": 0, "audio": "Test09_11.mp3"}, {"n": 12, "part": 2, "q": "Do you know how to use this new oven?", "qko": "이 새 오븐을 사용하는 방법을 아시나요?", "opts": ["It didn't cost much.", "When we return from dinner.", "Sure, let me show you how."], "optko": ["그것은 비용이 많이 들지 않았어요.", "우리가 저녁 식사에서 돌아온 후에요.", "물론이죠, 어떻게 하는 건지 제가 보여드릴게요."], "ans": 2, "audio": "Test09_12.mp3"}, {"n": 13, "part": 2, "q": "Putting this bookcase together was fairly easy, wasn't it?", "qko": "이 책꽂이를 조립하는 것은 꽤 쉬웠어요, 안 그런가요?", "opts": ["It wasn't there when I looked.", "Yes, it only took 10 minutes.", "My personal collection of novels."], "optko": ["제가 봤을 때는 거기에 없었어요.", "네, 10분밖에 안 걸렸어요.", "제 개인적인 소설 소장품이에요."], "ans": 1, "audio": "Test09_13.mp3"}, {"n": 14, "part": 2, "q": "Would you be able to mail this parcel today?", "qko": "오늘 이 소포를 보내주실 수 있나요?", "opts": ["Of course.", "I checked my mail last night.", "Sorry, the luncheon was yesterday."], "optko": ["물론이죠.", "제가 지난밤에 우편물을 확인했어요.", "죄송하지만, 오찬은 어제였어요."], "ans": 0, "audio": "Test09_14.mp3"}, {"n": 15, "part": 2, "q": "How did you do on your exams last semester?", "qko": "당신은 지난 학기에 시험을 어떻게 봤나요?", "opts": ["For biology and history.", "I did well. Thanks for asking.", "It lasted longer than I thought."], "optko": ["생물학과 역사학이요.", "잘 봤어요. 물어봐 주셔서 감사합니다.", "제가 생각했던 것보다 오래 지속됐어요."], "ans": 1, "audio": "Test09_15.mp3"}, {"n": 16, "part": 2, "q": "Are travel expenses covered by our firm?", "qko": "출장 비용이 우리 회사에 의해 충당되나요?", "opts": ["Only airfare and accommodations.", "We're a manufacturing company.", "That's quite expensive."], "optko": ["항공 운임과 숙박 시설만요.", "우린 제조 회사예요.", "그건 꽤 비싸네요."], "ans": 0, "audio": "Test09_16.mp3"}, {"n": 17, "part": 2, "q": "The demonstration of our new product went extremely well this morning.", "qko": "오늘 아침에 우리 신제품 시연이 매우 순조롭게 진행되었어요.", "opts": ["The expo continues throughout the week.", "A limited number of products are still available.", "Yes, the director seemed impressed."], "optko": ["박람회는 일주일 내내 계속돼요.", "한정된 수의 제품들을 아직 구할 수 있어요.", "네, 부장이 인상 깊게 생각하는 것 같았어요."], "ans": 2, "audio": "Test09_17.mp3"}, {"n": 18, "part": 2, "q": "The gym should replace these cycling machines, shouldn't it?", "qko": "체육관은 이 사이클링 기기들을 교체해야 해요, 안 그런가요?", "opts": ["Sam would rather walk there instead.", "They don't seem very old to me.", "Those are the membership rates."], "optko": ["Sam은 차라리 그곳에 대신 걸어가고 싶어 할 거예요.", "제가 보기에 그것들은 별로 낡아 보이지 않아요.", "그것들은 회원제 요금이에요."], "ans": 1, "audio": "Test09_18.mp3"}, {"n": 19, "part": 2, "q": "When do I need to return this manual to you?", "qko": "제가 언제 당신에게 이 설명서를 돌려드려야 하나요?", "opts": ["I expect to speak at a seminar.", "He'll look at the instructions.", "By noon at the latest."], "optko": ["저는 세미나에서 발표할 것 같아요.", "그가 지시 사항들을 살펴볼 거예요.", "늦어도 정오까지요."], "ans": 2, "audio": "Test09_19.mp3"}, {"n": 20, "part": 2, "q": "Do you want me to look over our budget figures?", "qko": "제가 우리의 예산액을 검토할까요?", "opts": ["Over 100 attendees.", "Thanks. That would help a lot.", "To the accounting division."], "optko": ["백 명 이상의 참석자요.", "고마워요. 그건 큰 도움이 될 거예요.", "회계 부서로요."], "ans": 1, "audio": "Test09_20.mp3"}, {"n": 21, "part": 2, "q": "Who will be in charge of organizing the safety drill?", "qko": "안전 훈련 준비를 누가 담당할 건가요?", "opts": ["Either Angela or Mathew.", "They won't go.", "Actually, it's still too large."], "optko": ["Angela 아니면 Mathew요.", "그들은 가지 않을 거예요.", "사실은, 그것은 여전히 너무 커요."], "ans": 0, "audio": "Test09_21.mp3"}, {"n": 22, "part": 2, "q": "Have you met our new board chairman?", "qko": "당신은 우리의 새 이사회장을 만났나요?", "opts": ["No, it wasn't posted on the bulletin board.", "We were introduced this morning.", "These chairs are very comfortable."], "optko": ["아니요, 그것은 게시판에 게시되지 않았어요.", "우리는 오늘 아침에 인사했어요.", "이 의자들은 매우 편해요."], "ans": 1, "audio": "Test09_22.mp3"}, {"n": 23, "part": 2, "q": "Which store did you just stop at?", "qko": "당신은 방금 어느 상점에 들렀나요?", "opts": ["A boutique called Taylor Apparel.", "I usually do my shopping on weekends.", "You did a wonderful job."], "optko": ["Taylor Apparel이라고 불리는 부티크요.", "저는 주로 주말에 쇼핑을 해요.", "당신은 정말 잘했어요."], "ans": 0, "audio": "Test09_23.mp3"}, {"n": 24, "part": 2, "q": "Why do you plan to leave so early?", "qko": "당신은 왜 이렇게 일찍 떠날 계획인가요?", "opts": ["At 5 o'clock, precisely.", "Yes, as soon as possible.", "My tennis club plays today."], "optko": ["정확하게 5시에요.", "네, 가능한 한 빨리요.", "제 테니스 클럽이 오늘 경기를 해요."], "ans": 2, "audio": "Test09_24.mp3"}, {"n": 25, "part": 2, "q": "Shall we meet the investors at the construction site or in our office?", "qko": "투자자들을 공사 현장에서 만날까요, 아니면 우리 사무실에서 만날까요?", "opts": ["They want to tour the location.", "His office is the door on your left.", "I'll have the contractor come as well."], "optko": ["그들은 그 부지를 견학하고 싶어 해요.", "그의 사무실은 당신의 왼쪽 방이에요.", "제가 계약자도 오게 할게요."], "ans": 0, "audio": "Test09_25.mp3"}, {"n": 26, "part": 2, "q": "Where would you like me to file all of these old business reports?", "qko": "제가 이 오래된 사업 보고서들을 모두 어디에 보관할까요?", "opts": ["John printed the company documents.", "They're profiles on past clients.", "In the white cabinet."], "optko": ["John이 회사 문서들을 인쇄했어요.", "그것들은 과거 고객들의 프로필이에요.", "흰색 진열장 안에요."], "ans": 2, "audio": "Test09_26.mp3"}, {"n": 27, "part": 2, "q": "What was the conference about?", "qko": "회의는 무엇에 관한 것이었나요?", "opts": ["It was held in Mexico City.", "Yes, we want to go.", "Advertising methods."], "optko": ["그것은 멕시코 시티에서 개최됐어요.", "네, 우리는 가고 싶어요.", "광고 기법들이요."], "ans": 2, "audio": "Test09_27.mp3"}, {"n": 28, "part": 2, "q": "These pamphlets need to be put into envelopes.", "qko": "이 소책자들은 봉투에 넣어져야 해요.", "opts": ["I'll get some from the supply room.", "I bought them at the stationery store.", "Thanks, but I don't need any more."], "optko": ["제가 비품실에서 몇 개 가져올게요.", "저는 그것들을 문구점에서 샀어요.", "감사하지만 더는 필요하지 않아요."], "ans": 0, "audio": "Test09_28.mp3"}, {"n": 29, "part": 2, "q": "How can I make a payment for my cable service?", "qko": "제 케이블 서비스 대금을 어떻게 납부하면 되나요?", "opts": ["She's not able to pay it this afternoon.", "You can do that on our Web site.", "Yes, more than 50 channels."], "optko": ["그녀는 오늘 오후에 그것을 납부할 수 없어요.", "저희 웹사이트에서 하실 수 있습니다.", "네, 50개 이상의 채널이요."], "ans": 1, "audio": "Test09_29.mp3"}, {"n": 30, "part": 2, "q": "Would you like a hand contacting our donors?", "qko": "우리의 기부자들에게 연락하는 것을 도와드릴까요?", "opts": ["At the previous fundraiser.", "Patrick is helping me.", "The contract was completed."], "optko": ["지난번 모금 행사에서요.", "Patrick이 저를 돕고 있어요.", "그 계약은 완료되었어요."], "ans": 1, "audio": "Test09_30.mp3"}, {"n": 31, "part": 2, "q": "The color of that carpet sample seems far too bright.", "qko": "저 카펫 샘플의 색깔은 너무 밝은 것 같아요.", "opts": ["After we spread them around the room.", "Some rugs for our main reception area.", "Would you like to see something a bit darker?"], "optko": ["우리가 그것들을 방에 펼친 후에요.", "우리의 가장 큰 응접실에 둘 깔개들 몇 개요.", "조금 더 어두운 것을 보시겠어요?"], "ans": 2, "audio": "Test09_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test09_32-34.mp3", "qs": [{"n": 32, "q": "What event is taking place?", "opts": ["A business seminar", "An awards ceremony", "A charity fund-raiser", "A shareholders' meeting"], "ans": 2, "ko": "무슨 행사가 열리고 있는가?"}, {"n": 33, "q": "What information does the man ask the woman for?", "opts": ["A company name", "A work address", "A seat number", "A confirmation code"], "ans": 0, "ko": "남자는 여자에게 무슨 정보를 요청하는가?"}, {"n": 34, "q": "What will the man most likely do next?", "opts": ["Bring out a beverage", "Escort a guest", "Check a list", "Explain an agenda"], "ans": 1, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Welcome to the Excel Corporate Charity Event. If you tell me your full name and the company you are affiliated with, I can let you know which seat you have been assigned to.", "ko": "Excel사의 자선 행사에 오신 것을 환영합니다. 저에게 성함과 가입한 회사를 알려주시면, 배정된 좌석을 안내해 드릴 수 있습니다."}, {"sp": "W", "en": "My name is Prema Khan, and I'm representing my investment firm, Mumbai International. But before I find my seat, is there a place where I can hang my coat? I'd rather not keep it with me all night.", "ko": "제 이름은 Prema Khan이고, 투자 회사인 Mumbai International사를 대표하고 있습니다. 그런데 좌석을 찾기 전에, 제 코트를 걸 수 있는 곳이 있나요? 이걸 저녁 내내 갖고 있고 싶지 않아서요."}, {"sp": "M", "en": "First, let me lead you to your table. Then, I would be happy to check your coat for you.", "ko": "우선, 테이블로 안내해 드리겠습니다. 그다음에, 기꺼이 손님의 코트를 보관해 드리겠습니다."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음 → 호주식 발음", "audio": "Test09_35-37.mp3", "qs": [{"n": 35, "q": "What are the speakers mainly discussing?", "opts": ["A client contract", "A project deadline", "A flight booking", "A company regulation"], "ans": 3, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 36, "q": "Which department do the men most likely work in?", "opts": ["Human resources", "Accounting", "Sales", "Technology"], "ans": 3, "ko": "남자들은 어느 부서에서 일하는 것 같은가?"}, {"n": 37, "q": "What does the woman say about the company's partners?", "opts": ["Some provide technical services.", "They are satisfied with a change.", "Some are located in other countries.", "They plan to renovate their headquarters."], "ans": 2, "ko": "여자는 회사의 파트너들에 관해 무엇을 말하는가?"}], "script": [{"sp": "W", "en": "Hey, Mike and Floyd. Did you guys see the memo from human resources about the upcoming changes to the travel expense policy?", "ko": "안녕하세요, Mike와 Floyd. 출장비 방침에 대한 앞으로의 변화들에 관해 인사부에서 보낸 회람을 봤나요?"}, {"sp": "M1", "en": "Yes. I'm glad the company has decided to increase the amount that employees can be reimbursed to $5,000 per trip.", "ko": "네. 직원들이 상환받을 수 있는 금액을 출장당 5,000달러로 인상하기로 회사가 결정했다니 기쁘네요."}, {"sp": "W", "en": "Don't you think it's a bit high? On my last business trip, I didn't spend more than $1,600 for all my travel expenses.", "ko": "그게 약간 높다고 생각하지 않나요? 지난 출장에서, 저는 전체 출장비로 1,600달러 이상을 쓰지 않았어요."}, {"sp": "M1", "en": "Sure . . . but you and the other sales staff don't have to travel internationally.", "ko": "그렇죠… 하지만 당신과 다른 영업부 직원들은 국제적으로 출장을 갈 필요가 없잖아요."}, {"sp": "M2", "en": "Exactly. Members of the technology team, like Floyd and I, go abroad frequently to complete projects.", "ko": "바로 그거예요. Floyd와 저와 같은 기술팀의 팀원들은 프로젝트들을 완료하기 위해 해외에 자주 가요."}, {"sp": "W", "en": "Oh, right. I forgot that your department is putting in the computer system for one of our international partners' new headquarters.", "ko": "아, 맞아요. 여러분 부서가 우리 회사의 국제 파트너들의 새로운 본사 중 한 곳에 컴퓨터 시스템을 설치하고 있다는 것을 제가 잊었네요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test09_38-40.mp3", "qs": [{"n": 38, "q": "What is the topic of the conversation?", "opts": ["Prototype design plans", "Quality control methods", "Computer equipment", "Software installation"], "ans": 2, "ko": "대화의 주제는 무엇인가?"}, {"n": 39, "q": "What will the woman ask the office manager to do?", "opts": ["Place an order", "Hire a designer", "Cancel an assignment", "Select a model"], "ans": 0, "ko": "여자는 사무장에게 무엇을 하도록 요청할 것인가?"}, {"n": 40, "q": "What does the man say he can do?", "opts": ["Deal with staff complaints", "Extend a submission deadline", "Request funds for a project", "Find out employee preferences"], "ans": 3, "ko": "남자는 무엇을 할 수 있다고 말하는가?"}], "script": [{"sp": "M", "en": "Ms. Ellison, is it possible for us to get new computer monitors for the office? The graphic designers say the resolution quality of our current computer screens is rather poor. It seems to negatively impact their work.", "ko": "Ms. Ellison, 저희가 사무실에 둘 새 컴퓨터 모니터들을 사는 것이 가능할까요? 그래픽 디자이너들이 우리의 현재 컴퓨터 화면들의 해상도 질이 다소 좋지 않다고 말해요. 그게 그들의 작업에 부정적인 영향을 주는 것 같아요."}, {"sp": "W", "en": "I've been meaning to do that for quite a while. We couldn't afford to upgrade in the past, but we have enough funds this month. I'll ask the office manager to order high-resolution monitors for all our designers.", "ko": "꽤 오랫동안 그렇게 할 예정이었어요. 우리가 과거에는 개선을 할 여유가 없었지만, 이번 달에는 충분한 자금이 있어요. 사무장에게 모든 디자이너들을 위한 고해상도 모니터들을 주문하라고 요청할게요."}, {"sp": "M", "en": "They will certainly appreciate that. And if you're unsure about which models to get, I can ask the staff for their opinions on the matter.", "ko": "그들은 틀림없이 그것을 고맙게 생각할 거예요. 그리고 어떤 모델을 사야 할지 잘 모르시겠다면, 제가 직원들에게 그 사안에 대한 그들의 의견을 물어볼 수 있어요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test09_41-43.mp3", "qs": [{"n": 41, "q": "What problem does the woman identify?", "opts": ["She forgot about some plans.", "She cannot go to an event.", "Her car needs to be fixed.", "Her entrance pass is lost."], "ans": 2, "ko": "여자는 어떤 문제를 밝히는가?"}, {"n": 42, "q": "What solution does the man suggest?", "opts": ["Printing out some coupons", "Taking public transportation", "Riding with someone else", "Contacting a customer"], "ans": 2, "ko": "남자는 어떤 해결책을 제안하는가?"}, {"n": 43, "q": "What does the woman inquire about?", "opts": ["Whether she can be picked up", "If she must change her schedule", "How far away a location is", "Where a friend wants to go"], "ans": 0, "ko": "여자는 무엇에 관해 문의하는가?"}], "script": [{"sp": "W", "en": "Hi, Adrian. I need to talk to you about our plans for tomorrow. I know I offered to drive us to the amusement park in the morning, but I don't think I'll be able to. For some reason, my car won't start. I'm going to have it towed to a repair center to be fixed.", "ko": "안녕하세요, Adrian. 우리의 내일 계획에 대해서 당신에게 이야기해야 해요. 제가 아침에 제 차로 놀이공원까지 가자고 제안한 건 아는데, 그럴 수 없을 것 같아요. 무슨 이유인지, 제 차가 시동이 안 걸려요. 차를 수리 센터에 견인시켜서 수리를 받을 거예요."}, {"sp": "M", "en": "That's OK. Rachel should still have room in her van, so I'm sure we can ride with her instead.", "ko": "괜찮아요. Rachel의 승합차에 아직 자리가 있을 테니, 우리는 대신 그녀와 함께 타면 될 거라고 확신해요."}, {"sp": "W", "en": "Great. Do you think she will also be able to pick me up from my house? Since I won't have a vehicle, it will be hard for me to meet up with everyone.", "ko": "잘됐네요. 그녀가 저를 태우러 저희 집으로 올 수 있을 것 같나요? 제가 차가 없을 테니, 모두와 만나기가 어려울 거예요."}, {"sp": "M", "en": "I don't think she'll mind, but I'll ask her anyway.", "ko": "그녀가 싫어할 것 같지는 않지만, 그래도 한번 물어볼게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test09_44-46.mp3", "qs": [{"n": 44, "q": "Where do the speakers most likely work?", "opts": ["At a recruitment agency", "At an architectural firm", "At a financial institution", "At a law office"], "ans": 1, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 45, "q": "What will happen during the meeting next week?", "opts": ["A contract will be finalized.", "A schedule will be discussed.", "A representative will be introduced.", "A design will be revealed."], "ans": 1, "ko": "다음 주 회의 동안 무슨 일이 일어날 것인가?"}, {"n": 46, "q": "Why does the man say, \"Jenna Adams will be the team leader\"?", "opts": ["To stress the importance of a project", "To indicate that a colleague was promoted", "To encourage the woman to participate", "To correct the woman's assumption"], "ans": 3, "ko": "남자는 왜 \"Jenna Adams가 팀장이 될 거예요\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Beth . . . I'm glad I caught you. Our company is designing Fieldstone Financial's new Portland office building. I'm meeting with one of their representatives next week to talk about the project timetable, and I'd like you to join me.", "ko": "Beth… 때마침 당신을 만나서 기쁘네요. 우리 회사는 Fieldstone Financial사의 새로운 포틀랜드 사무실 건물을 설계하고 있어요. 저는 다음 주에 프로젝트 일정에 관해 논의하기 위해 그 회사의 직원들 중 한 명과 만날 것인데, 당신이 저와 함께했으면 해요."}, {"sp": "W", "en": "OK. I heard about the new contract, but I didn't know I'd be involved. I assume you're going to be running the project, right?", "ko": "좋아요. 새로운 계약에 관해서는 들었는데, 저도 참여하게 될지는 몰랐어요. 당신이 이 프로젝트를 운영할 것이라 짐작되네요, 그렇죠?"}, {"sp": "M", "en": "Jenna Adams will be the team leader. I'll only be involved in the early stages.", "ko": "Jenna Adams가 팀장이 될 거예요. 저는 초기 단계에만 관여할 거고요."}, {"sp": "W", "en": "This is going to be her first time in a management role, isn't it?", "ko": "이번이 그녀가 처음으로 관리직을 맡는 것일 거예요, 그렇지 않나요?"}, {"sp": "M", "en": "Yes. But she has worked on similar projects in the past, so I'm confident that she will do well.", "ko": "네. 하지만 그녀가 과거에 비슷한 프로젝트들을 해봐서, 잘할 거라고 확신해요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test09_47-49.mp3", "qs": [{"n": 47, "q": "Why did the woman visit the office?", "opts": ["To interview job candidates", "To serve some customers", "To check on a program", "To ask about a schedule"], "ans": 2, "ko": "여자는 왜 사무실을 방문했는가?"}, {"n": 48, "q": "Why is the man pleased?", "opts": ["A job is now available.", "A request was approved.", "Some software works well.", "Customers gave positive feedback."], "ans": 2, "ko": "남자는 왜 기뻐하는가?"}, {"n": 49, "q": "What will the man most likely do next week?", "opts": ["Train some personnel", "Transfer departments", "Upgrade a system", "Start a new position"], "ans": 0, "ko": "남자는 다음 주에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Hey, Larry. How are things going here at the ticketing office? I just want to check and see if the new software we installed is working OK.", "ko": "안녕하세요, Larry. 이곳 매표소 일은 어떤가요? 우리가 설치한 새 소프트웨어가 잘 작동하고 있는지만 확인해보고 싶어요."}, {"sp": "M", "en": "Oh, it's been wonderful! It is easy to use and saves a lot of time. I've been able to serve twice as many customers as usual this morning.", "ko": "아, 지금까지는 아주 좋아요! 사용하기도 쉽고 시간을 많이 절약해줘요. 저는 오늘 아침에 평소보다 두 배나 많은 고객들을 응대할 수 있었어요."}, {"sp": "W", "en": "That's good news. I was hoping it would make your job easier. Do you think any other agents will need training on how to use it?", "ko": "그거 좋은 소식이네요. 그것으로 인해 당신의 작업이 더 수월해지길 바라고 있었어요. 다른 직원들이 그것을 어떻게 사용하는지에 대한 훈련이 필요할까요?"}, {"sp": "M", "en": "Yes. Two new employees are starting next week, so I'll have to provide them with some instructions.", "ko": "네. 다음 주부터 신입 직원 두 명이 일을 시작해서, 제가 그들에게 교육을 해줘야 할 거예요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test09_50-52.mp3", "qs": [{"n": 50, "q": "Where most likely are the speakers?", "opts": ["At a clothing boutique", "At a retail outlet", "At a department store", "At a beauty salon"], "ans": 3, "ko": "화자들은 어디에 있는 것 같은가?"}, {"n": 51, "q": "What does the woman want to do?", "opts": ["Get a hair cut", "Make a purchase", "Arrange an appointment", "Speak to a manager"], "ans": 1, "ko": "여자는 무엇을 하고 싶어 하는가?"}, {"n": 52, "q": "What does the man say about Nature's Touch brand?", "opts": ["It is used by some of the stylists.", "It is made with organic ingredients.", "It is completely sold out.", "It is on sale."], "ans": 3, "ko": "남자는 Nature's Touch 브랜드에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "Welcome to Prim Hair. Do you have an appointment with one of our stylists today?", "ko": "Prim Hair에 오신 것을 환영합니다. 오늘 저희 미용사 중 한 명에게 예약을 하셨나요?"}, {"sp": "W", "en": "Oh, I've stopped in to view your selection of merchandise. I use Nature's Touch shampoo and was told that you carry the brand. If so, I'd like to buy some.", "ko": "아, 저는 이곳의 상품을 보기 위해 들렀어요. 저는 Nature's Touch 샴푸를 쓰는데 여기서 그 브랜드를 취급한다고 들었어요. 그렇다면, 몇 개 사고 싶어요."}, {"sp": "M", "en": "Yes, we do. Also, we're having a promotion on that brand this week, so everything from that line is available for 10 percent off its normal retail price.", "ko": "네, 맞습니다. 또한, 저희는 이번 주에 그 브랜드에 대해 판촉 행사를 하고 있어서, 그 라인의 모든 제품은 정상 소매가에서 10퍼센트 할인된 가격에 이용 가능합니다."}, {"sp": "W", "en": "That's great. I'll look over what you have in stock.", "ko": "잘됐네요. 어떤 것들이 재고로 있는지 살펴볼게요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test09_53-55.mp3", "qs": [{"n": 53, "q": "What did the woman recently do?", "opts": ["Gave a presentation", "Visited a store", "Joined a team", "Reviewed a document"], "ans": 3, "ko": "여자는 최근에 무엇을 했는가?"}, {"n": 54, "q": "What problem does the woman mention?", "opts": ["A financial report was inaccurate.", "A new service failed.", "A company's sales have decreased.", "A competitor offers larger discounts."], "ans": 2, "ko": "여자는 무슨 문제를 언급하는가?"}, {"n": 55, "q": "Why does the man say, \"our customers have to visit our shops in person\"?", "opts": ["To explain a process", "To reject a suggestion", "To confirm a decision", "To indicate a problem"], "ans": 3, "ko": "남자는 왜 \"our customers have to visit our shops in person\"이라고 말하는가?"}], "script": [{"sp": "W", "en": "I just went through the financial report prepared by the accounting team. I'm a little concerned because sales have declined at many of the cosmetics stores we operate.", "ko": "회계팀이 준비한 재무 보고서를 이제 막 검토했어요. 우리가 운영하는 다수의 화장품 가게들에서 매출이 하락해 조금 걱정이 되네요."}, {"sp": "M", "en": "I know. Apparently, our main competitor now offers an online service. Customers can order products through the company's Web site and have them delivered on the same day. In contrast, our customers have to visit our shops in person.", "ko": "그러니까요. 듣자 하니, 우리의 주요 경쟁 업체가 이제 온라인 서비스를 제공하대요. 고객들은 그 회사의 웹사이트에서 제품을 주문하고 당일에 배송되도록 할 수 있어요. 그에 반해서, 우리 고객들은 우리 가게들을 직접 방문해야 해요."}, {"sp": "W", "en": "That's not good. We need to figure out a way to be more competitive.", "ko": "그거 안 좋네요. 우리는 더욱 경쟁력을 갖출 방법을 생각해내야 해요."}, {"sp": "M", "en": "Well, the solution seems obvious . . . We should develop a similar service.", "ko": "음, 해결책은 명백한 것 같아요… 우리는 비슷한 서비스를 개발해야 해요."}, {"sp": "W", "en": "Yeah. I'm going to put together a presentation about this for the CEO.", "ko": "맞아요. 제가 최고 경영자를 위해 이것에 관한 발표를 준비할게요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test09_56-58.mp3", "qs": [{"n": 56, "q": "What does the man plan to do on Saturday?", "opts": ["Stop by a trade show", "Go to a photography class", "Attend an exhibit opening", "Participate in a workshop"], "ans": 2, "ko": "남자는 토요일에 무엇을 할 계획인가?"}, {"n": 57, "q": "What does the woman say about her friend?", "opts": ["He gave away the tickets.", "He has another commitment.", "He took some photos.", "He already had lunch."], "ans": 1, "ko": "여자는 자신의 친구에 관해 무엇을 말하는가?"}, {"n": 58, "q": "What will the man probably do before going to Mendez Gallery?", "opts": ["Explore a museum", "Meet a relative", "Contact a colleague", "Visit a dining establishment"], "ans": 3, "ko": "남자는 Mendez 미술관에 가기 전에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Hi, Brenda. Do you have any plans for this Saturday? I was hoping to go to the opening of a photo exhibit at Mendez Gallery with some other members from our department. Would you like to come with us?", "ko": "안녕하세요, Brenda. 이번 토요일에 계획이 있나요? 저는 저희 부서의 몇몇 다른 팀원들과 Mendez 미술관의 사진전 개막에 가길 바라고 있었어요. 저희와 함께 가시겠어요?"}, {"sp": "W", "en": "Thanks for the invitation. I was supposed to meet my friend Peter, but he called and said he couldn't make it due to a family obligation. So, I'd be happy to come with you to the exhibit instead.", "ko": "초대해 주셔서 감사해요. 저는 제 친구 Peter를 만나기로 되어 있었는데, 그가 전화해서 가족과 관련된 일 때문에 약속을 지키지 못할 거라고 말했어요. 그래서, 대신 당신과 함께 전시회에 가면 좋을 것 같아요."}, {"sp": "M", "en": "Wonderful! I'm sure you'll like the nature and landscape pictures at the gallery. By the way, we're thinking of having lunch at a café in the area before going to the gallery. You are more than welcome to join us.", "ko": "좋아요! 당신은 분명히 미술관의 자연과 풍경 사진들을 좋아할 거예요. 그건 그렇고, 저희는 미술관에 가기 전에 근처 카페에서 점심을 먹으려고 생각 중이에요. 당신이 함께 가는 건 정말 환영이에요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test09_59-61.mp3", "qs": [{"n": 59, "q": "What is the man inquiring about?", "opts": ["The installation of some equipment", "The deadline for a project", "The status of a delivery", "The progress of some research"], "ans": 2, "ko": "남자는 무엇에 관해 문의하고 있는가?"}, {"n": 60, "q": "Where most likely does the man work?", "opts": ["At a laboratory", "At a shipping company", "At an electronics retailer", "At a warehouse"], "ans": 0, "ko": "남자는 어디에서 일하는 것 같은가?"}, {"n": 61, "q": "Why does the man want to get the item soon?", "opts": ["He has to replace a broken machine.", "He will conduct a product analysis.", "He needs to test its accuracy.", "He requires it for his upcoming work."], "ans": 3, "ko": "남자는 왜 물품을 빨리 받기를 원하는가?"}], "script": [{"sp": "M", "en": "Hello, this is Joshua Curtis from Ridley Institute. We were supposed to receive a piece of specialty laboratory equipment from your store last Friday, but it wasn't delivered.", "ko": "안녕하세요, 저는 Ridley 연구소의 Joshua Curtis입니다. 저희는 지난 금요일에 당신의 상점으로부터 전문 실험 장비를 하나 받기로 되어 있었는데, 그것이 배송되지 않았어요."}, {"sp": "W", "en": "Oh, I apologize for that. Your item was most likely included in the recent shipment, which was delayed due to bad weather. Now that weather conditions have improved, your order will be mailed out today.", "ko": "아, 그것에 대해 사과드립니다. 귀하의 물품은 아마도 날씨가 좋지 않아서 지연된 최근의 선적에 포함되었던 것 같습니다. 이제 날씨가 나아졌으니, 귀하의 주문품은 오늘 발송될 겁니다."}, {"sp": "M", "en": "I hope I get the machine soon because we'll need it for our next research project. Do you know when the shipment will arrive here?", "ko": "저희 다음 연구 프로젝트에 필요할 것이기 때문에 그 기계를 빨리 받아봤으면 해요. 선적이 언제 이곳에 도착할지 아시나요?"}, {"sp": "W", "en": "It should take about three to five business days.", "ko": "영업일로 3일에서 5일 정도 걸릴 거예요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test09_62-64.mp3", "qs": [{"n": 62, "q": "Why is the event being held?", "opts": ["To announce a manager's promotion", "To commemorate a company's founding", "To celebrate a branch opening", "To introduce a potential client"], "ans": 3, "ko": "행사는 왜 열리게 될 것인가?"}, {"n": 63, "q": "Look at the graphic. Which building will the man visit in the afternoon?", "opts": ["Building A", "Building B", "Building C", "Building D"], "ans": 0, "ko": "시각 자료를 보시오. 남자는 오후에 어떤 건물에 방문할 것인가?"}, {"n": 64, "q": "What did the woman do yesterday?", "opts": ["Met with a manager", "Sent an e-mail", "Paid a deposit", "Revised a handbook"], "ans": 3, "ko": "여자는 어제 무엇을 했는가?"}], "script": [{"sp": "W", "en": "I just heard that the CEO of Lorcam Industries will visit our office this afternoon. Apparently, she is considering placing a large order with us.", "ko": "저는 방금 Lorcam Industries사의 최고 경영자가 오늘 오후에 우리 사무실을 방문할 것이라고 들었어요. 듣자 하니, 그녀가 우리에게 대량 주문하는 것을 고려하고 있나 봐요."}, {"sp": "M", "en": "I know. Our director wants me to organize a dinner so that our management team can meet her.", "ko": "알아요. 우리 관리자는 경영진이 그녀를 만날 수 있도록 제가 저녁 식사를 계획하기를 원해요."}, {"sp": "W", "en": "Have you found a suitable place yet?", "ko": "적절한 장소를 찾았나요?"}, {"sp": "M", "en": "Yes. The Belleview Bistro on the corner of Johnson Street and Elm Avenue . . . I'm going to stop by there this afternoon to pay the deposit for a private room.", "ko": "네. Johnson가와 Elm가의 모퉁이에 있는 The Belleview Bistro요… 저는 개인실을 위한 보증금을 지불하기 위해 오늘 오후에 그곳에 들를 거예요."}, {"sp": "W", "en": "Sounds good. Oh, by the way . . . I made the changes you requested to the employee manual yesterday.", "ko": "좋아요. 아, 그건 그렇고… 제가 어제 직원 안내서에 당신이 요청하신 수정을 했어요."}, {"sp": "M", "en": "Great. Just e-mail it to me, and I'll have a look at it.", "ko": "훌륭해요. 그걸 저한테 이메일로 보내주시면, 제가 살펴볼게요."}], "gimg": "hk2_t9_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test09_65-67.mp3", "qs": [{"n": 65, "q": "Why does the man apologize to the woman?", "opts": ["He was slow to wait on a table.", "He made a minor mistake.", "An entrée is no longer available.", "A line was longer than expected."], "ans": 0, "ko": "남자는 왜 여자에게 사과하는가?"}, {"n": 66, "q": "Look at the graphic. Which side dish does the woman select?", "opts": ["House salad", "Lemon kale salad", "Roasted potatoes", "Pan-fried green beans"], "ans": 2, "ko": "시각 자료를 보시오. 여자는 어느 곁들임 요리를 선택하는가?"}, {"n": 67, "q": "What does the man offer to do?", "opts": ["Modify an existing order", "Bring another menu", "Speak with a restaurant manager", "Inquire about a beverage"], "ans": 3, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "M", "en": "Sorry, ma'am. I know you've been sitting here for a few minutes, but I had to finish up at another table before serving you. Have you had a chance to review the menu?", "ko": "죄송합니다, 부인. 손님께서 몇 분 동안 이곳에 앉아계셨던 것을 알지만, 손님을 응대하기 전에 다른 테이블을 마무리해야 했어요. 메뉴를 좀 살펴보셨나요?"}, {"sp": "W", "en": "No need to apologize. As for food, I think I know what I want—the olive and artichoke pasta, please.", "ko": "사과하실 필요 없어요. 음식에 대해서는, 제가 원하는 것을 알 것 같아요. 올리브와 아티초크 파스타로 주세요."}, {"sp": "M", "en": "An excellent choice. And for your side dish? The lemon kale salad is particularly wonderful.", "ko": "탁월한 선택이시네요. 그리고 곁들임 요리는요? 레몬 케일 샐러드가 특히 훌륭합니다."}, {"sp": "W", "en": "That sounds a bit light to me. I think I'll go with the third choice. Also . . . do you have chamomile tea? I'd really enjoy some.", "ko": "저한테는 조금 가볍게 들리네요. 저는 세 번째 선택지로 할게요. 그리고… 캐모마일 차가 있나요? 정말로 마시고 싶어요."}, {"sp": "M", "en": "Let me ask our kitchen staff when I put in your order. I'll let you know shortly.", "ko": "손님의 주문을 넣을 때 제가 저희 주방 직원에게 물어볼게요. 즉시 알려드리겠습니다."}], "gimg": "hk2_t9_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test09_68-70.mp3", "qs": [{"n": 68, "q": "Why must the speakers travel to Baltimore?", "opts": ["To give a presentation", "To launch a campaign", "To promote a new regional branch", "To consider an investment opportunity"], "ans": 0, "ko": "화자들은 왜 볼티모어로 가야 하는가?"}, {"n": 69, "q": "What was the man informed of?", "opts": ["An award nomination", "A client meeting", "A project deadline", "A reimbursement plan"], "ans": 3, "ko": "남자는 무엇에 대해 통지받았는가?"}, {"n": 70, "q": "Look at the graphic. Which flight most likely will the speakers take?", "opts": ["Flight 247", "Flight 451", "Flight 663", "Flight 819"], "ans": 2, "ko": "시각 자료를 보시오. 화자들은 어떤 항공편을 탈 것 같은가?"}], "script": [{"sp": "M", "en": "Did you hear we'll be taking a business trip to Baltimore soon?", "ko": "우리가 곧 볼티모어로 출장을 가게 될 거라는 소식을 들었어요?"}, {"sp": "W", "en": "Yeah. I found out about an hour ago that we've been selected to present our firm's annual sales figures to shareholders.", "ko": "네. 저는 한 시간 정도 전에 우리가 회사의 연례 매출액을 주주들에게 발표하도록 선정되었다는 것을 알게 되었어요."}, {"sp": "M", "en": "That's right. We've got a lot of things to prepare. But I'm looking forward to going to Baltimore. I've always wanted to visit there. Plus, I was informed that all of our costs will be covered.", "ko": "맞아요. 우리는 준비해야 할 것들이 많아요. 하지만 저는 볼티모어에 가는 것이 기대돼요. 저는 항상 그곳을 방문해 보고 싶었거든요. 게다가, 우리의 모든 경비가 보장될 거라고 통지받았어요."}, {"sp": "W", "en": "Oh, that reminds me . . . Ms. Owens asked me to book our flight. What time do you want to leave on June 6?", "ko": "아, 그러고 보니 생각나네요… Ms. Owens가 우리의 항공편을 예약해달라고 제게 부탁했어요. 6월 6일에 몇 시에 떠나고 싶으세요?"}, {"sp": "M", "en": "I have a big meeting that morning, so let's take the earliest flight in the afternoon.", "ko": "저는 그날 아침에 큰 회의가 있으니까, 오후에 있는 가장 빠른 항공편을 타도록 해요."}], "gimg": "hk2_t9_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test09_71-73.mp3", "qs": [{"n": 71, "q": "What is the purpose of the message?", "opts": ["To request a refund", "To report an issue", "To confirm an order", "To reschedule a meeting"], "ans": 1, "ko": "메시지의 목적은 무엇인가?"}, {"n": 72, "q": "According to the speaker, what is a benefit of the Weyden Platinum?", "opts": ["It has a powerful motor.", "It has multiple settings.", "It is simple to move around.", "It is available in various sizes."], "ans": 2, "ko": "화자에 따르면, Weyden Platinum의 이점은 무엇인가?"}, {"n": 73, "q": "What does the speaker recommend?", "opts": ["Seeing a device in person", "Getting an extended warranty", "Participating in a contest", "Returning an item to a shop"], "ans": 0, "ko": "화자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "Hello, this is Jamie Foster at Phoenix Merchandising. This message is for Ms. Helen Rohan. I need to inform you that the specific model of VelociClean vacuum cleaner that you ordered is out of stock. However, we do have something similar called the Weyden Platinum. It is lightweight and removes more dirt from carpets than other models. Because of its design, it's easy to control and move around any indoor space. And since we were unable to fulfill your original request, we can offer you free delivery if you purchase the Weyden product. If you're interested, you should visit our shop, and I'll show the vacuum to you.", "ko": "안녕하세요, 저는 Phoenix Merchandising사의 Jamie Foster입니다. 이 메시지는 Ms. Helen Rohan을 위한 것입니다. 귀하께서 주문하신 VelociClean 진공청소기의 특정 모델의 재고가 없음을 알려드리고자 합니다. 하지만, 저희는 이와 비슷한 Weyden Platinum이라는 모델이 있습니다. 이것은 가볍고 다른 모델들보다 카펫으로부터 더 많은 먼지를 제거합니다. 디자인 덕분에, 그것은 실내 어디에서나 조종하고 움직이기가 쉽습니다. 그리고 저희가 귀하의 본래 요구 사항을 이행하지 못했기 때문에, 귀하께서 이 Weyden 상품을 구매하시면 무료 배송을 제공해 드릴 수 있습니다. 관심 있으실 경우, 저희 가게를 방문해 주시면, 제가 그 청소기를 고객님께 보여드리겠습니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test09_74-76.mp3", "qs": [{"n": 74, "q": "What kind of product is being advertised?", "opts": ["An energy bar", "A breakfast cereal", "A sports beverage", "A frozen pizza"], "ans": 2, "ko": "어떤 종류의 상품이 광고되고 있는가?"}, {"n": 75, "q": "What does the speaker mention about Power Source?", "opts": ["It has been recommended by a celebrity.", "It was developed for professional athletes.", "It has received positive reviews.", "It includes several kinds of vitamins."], "ans": 3, "ko": "화자는 Power Source에 관해 무엇을 언급하는가?"}, {"n": 76, "q": "What does the speaker mean when he says, \"This won't last for long!\"?", "opts": ["A product is only available in certain seasons.", "A promotion is expected to be popular.", "A product line is scheduled to be launched.", "A sale will expire at the end of the month."], "ans": 1, "ko": "화자는 \"이것은 오래 지속되지 않을 것입니다!\"라고 말할 때 무엇을 의도하는가?"}], "script": [{"sp": "M", "en": "Are you interested in giving your workout a boost? Then try Power Source, the brand-new enhanced drink from Pure Athletics. Power Source is infused with various essential vitamins that will give you the extra energy you require during your favorite physical activity. And now, check out our special online promotion. If you fill out a short survey on our Web site, you will receive a coupon for a free bottle of our newest Power Source flavor, Berry Mix. But this offer is only good until supplies run out, so act now. This won't last for long!", "ko": "당신의 운동에 활력을 불어넣는 것에 관심이 있으신가요? 그렇다면 Pure Athletics의 새로운 강화 음료, Power Source를 마셔보세요. Power Source는 여러분이 가장 좋아하는 신체 활동을 하는 동안 필요한 여분의 활기를 제공해줄 다양한 필수 비타민으로 가득 차 있습니다. 자 이제, 저희의 특별 온라인 판촉 행사를 확인해 보세요. 저희 웹사이트에서 간단한 설문 조사를 작성하시면 Power Source의 최신 맛인 Berry Mix 한 병을 무료로 받을 수 있는 쿠폰 한 장을 받으실 것입니다. 하지만 이 제공은 재고가 다 떨어질 때까지만 유효하니, 지금 행동하세요. 이것은 오래 지속되지 않을 것입니다!"}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test09_77-79.mp3", "qs": [{"n": 77, "q": "Where does Mr. Powell most likely work?", "opts": ["At a real estate office", "At an architectural firm", "At an advertising agency", "At a Web design company"], "ans": 1, "ko": "Mr. Powell은 어디에서 일하는 것 같은가?"}, {"n": 78, "q": "What must the speaker do in the afternoon?", "opts": ["Stop by his office", "Supervise a construction project", "Go to an urgent meeting", "Revise some existing blueprints"], "ans": 2, "ko": "화자는 오후에 무엇을 해야만 하는가?"}, {"n": 79, "q": "Why does the speaker say, \"She's familiar with the plans for the house\"?", "opts": ["To agree with a colleague", "To approve a request", "To reassure a client", "To highlight a concern"], "ans": 2, "ko": "화자는 왜 \"그녀는 그 집을 위한 계획들에 대해 잘 알고 있습니다\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Good evening, Ms. Jameson. This is Richard Powell calling from Smithson & Howard. As you already know, we are supposed to get together at your office this afternoon to review design plans that my firm has created for your new home. However, an emergency meeting has come up, which I must go to at 1 P.M. Consequently, I can't visit you today but will be sending a colleague of mine, Lori Fielding, to take my place. She's familiar with the plans for the house. I apologize for the inconvenience and appreciate your understanding.", "ko": "안녕하세요, Ms. Jameson. 저는 Smithson & Howard사의 Richard Powell입니다. 이미 아시다시피, 저희 회사가 고객님의 새로운 집을 위해 만든 설계 계획들을 검토하기 위해 저희가 오늘 오후에 고객님의 사무실에서 만나기로 되어 있었습니다. 하지만, 제가 오후 1시에 가야 하는 긴급회의가 생겼습니다. 따라서, 저는 오늘 고객님을 방문할 수 없지만, 저를 대신해 제 동료인 Lori Fielding을 보낼 것입니다. 그녀는 그 집을 위한 계획들에 대해 잘 알고 있습니다. 불편을 끼쳐드려서 사과드리며 이해해 주셔서 감사합니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test09_80-82.mp3", "qs": [{"n": 80, "q": "What is the broadcast mainly about?", "opts": ["A local celebration", "A sports competition", "A new park attraction", "A city music institute"], "ans": 0, "ko": "방송은 주로 무엇에 관한 것인가?"}, {"n": 81, "q": "What does the speaker say parents will enjoy?", "opts": ["Some prices", "Some performances", "Some rides", "Some contests"], "ans": 1, "ko": "화자는 부모들이 무엇을 즐길 것이라고 말하는가?"}, {"n": 82, "q": "According to the speaker, what will happen at 8 P.M.?", "opts": ["A festival will come to an end.", "An official will be interviewed.", "A booth will be set up.", "A musical event will take place."], "ans": 3, "ko": "화자에 따르면, 오후 8시에 무슨 일이 일어날 것인가?"}], "script": [{"sp": "M", "en": "This is Patrick West reporting live for WRRE Eyewitness News. I'm here at West Wellington Park, and we've got warmer than usual temperatures, a nice breeze, and clear skies again on the last day of the annual Cherry Festival, so come on down. There's something for everyone. Kids will enjoy the exciting rides and games, parents will appreciate the musical and cultural shows, and both will love the delicious food being served by the many booths set up here. The festival will end tonight after the 8 P.M. Mississippi Mounds concert. I'll be joined by the event organizer after a short commercial break, so be sure to stay tuned.", "ko": "저는 WRRE Eyewitness 뉴스를 생방송으로 전해드리는 Patrick West입니다. 저는 이곳 West Wellington 공원에 나와 있으며, 연례 벚나무 축제의 마지막 날에 다시 평소보다 따뜻한 기온, 기분 좋은 산들바람, 그리고 맑은 하늘이 있으니, 이곳으로 오십시오. 모두를 위한 것이 있습니다. 아이들은 신나는 놀이기구와 게임을 즐길 것이고, 부모들은 음악과 문화 공연을 음미할 것이며, 양쪽 다 이곳에 설치된 많은 부스들이 제공하는 맛있는 음식을 좋아할 것입니다. 축제는 오늘 밤 오후 8시의 Mississippi Mounds 콘서트 이후에 끝날 것입니다. 짧은 광고 후에 행사 기획자와 함께할 것이니, 반드시 채널을 고정해주시기 바랍니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test09_83-85.mp3", "qs": [{"n": 83, "q": "What does the speaker say listeners will do?", "opts": ["Observe a professional chef", "Sample some appetizers", "Put on some aprons", "Cook multiple dishes"], "ans": 3, "ko": "화자는 청자들이 무엇을 할 것이라고 말하는가?"}, {"n": 84, "q": "What has the speaker placed on the counters for listeners?", "opts": ["Registration forms", "Recipe printouts", "Baking ingredients", "Kitchen utensils"], "ans": 1, "ko": "화자는 청자들을 위해 조리대에 무엇을 놓았는가?"}, {"n": 85, "q": "Why do listeners need a partner?", "opts": ["They are doing team-building exercises.", "They have to brainstorm ideas.", "There are limited cooking implements.", "There is a shortage of ingredients."], "ans": 2, "ko": "청자들은 왜 파트너가 필요한가?"}], "script": [{"sp": "M", "en": "Hello, everyone. It's a pleasure to have you all here at The Culinary House. Today, you will be learning how to make homemade pizza. This will be the first of three dishes that you're going to make. I've already set printed booklets on the counters containing all of the recipes that you'll need this morning. Please take them out and open up to the recipe on the second page. Before you start cooking this meal, however, you all need to break up into pairs. Since there aren't enough utensils for each student, everyone will have to find someone else to work with.", "ko": "여러분, 안녕하세요. 이곳 The Culinary House에서 여러분 모두를 만나게 되어 반갑습니다. 오늘, 여러분은 집에서 만든 피자를 만드는 방법을 배울 것입니다. 이것은 여러분이 만들 세 개의 음식들 중에 첫 번째가 될 것입니다. 오늘 아침에 여러분이 필요로 할 모든 조리법을 포함하는 인쇄된 소책자들을 제가 조리대에 이미 준비해 놓았습니다. 그것들을 꺼내서 두 번째 페이지에 있는 조리법을 펼쳐 주세요. 그러나, 이 음식을 요리하는 것을 시작하기 전에, 모두 두 명씩으로 나눠 주셔야 합니다. 각 학생들을 위한 충분한 주방용품이 없기 때문에, 여러분은 함께 일할 다른 사람을 찾아야 할 것입니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test09_86-88.mp3", "qs": [{"n": 86, "q": "Who most likely is the listener?", "opts": ["A curator", "A real estate agent", "An artist", "A gallery manager"], "ans": 2, "ko": "청자는 누구인 것 같은가?"}, {"n": 87, "q": "What does the speaker imply when she says, \"Electric Space has tall ceilings and a large back entrance\"?", "opts": ["A potential venue is ideal.", "A building was recently renovated.", "A location was accurately advertised.", "A rental facility is fairly priced."], "ans": 0, "ko": "화자는 \"Electric Space에는 높은 천장과 큰 후문이 있습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 88, "q": "What does the speaker instruct the listener to do?", "opts": ["Review the terms of a lease", "Inform her of a decision", "Stop by a gallery in person", "Submit a portfolio of work"], "ans": 1, "ko": "화자는 청자에게 무엇을 하라고 지시하는가?"}], "script": [{"sp": "W", "en": "Hello, Zack. My name is Allison Peng, and I'm calling from Creative Prime Agency. I've contacted several galleries in the Richmond area about your work and heard back from Electric Space downtown. The curator from that gallery expressed great interest in the contemporary paintings you created and said she'd be delighted to exhibit them there in October. I know you use oversized canvasses for your work, and Electric Space has tall ceilings and a large back entrance. So, please let me know your thoughts on the opportunity as soon as you can.", "ko": "안녕하세요, Zack. 저는 Allison Peng이고, Creative Prime 대행사에서 전화드립니다. 당신의 작품과 관련하여 리치먼드 지역의 여러 미술관에 연락해보았고, 도심에 있는 Electric Space로부터 답변을 받았습니다. 그 미술관의 큐레이터가 당신이 창작한 현대 회화 작품들에 큰 관심을 보였고 그 작품들을 10월에 그곳에서 전시하게 된다면 아주 기쁠 것이라고 말했습니다. 저는 당신이 작품에 대형 캔버스를 사용하는 것을 알고 있으며, Electric Space에는 높은 천장과 큰 후문이 있습니다. 그러니, 가능한 한 빨리 이 기회에 대한 당신의 생각을 제게 알려주세요."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test09_89-91.mp3", "qs": [{"n": 89, "q": "Who does the speaker say is coming to visit?", "opts": ["The head of a research facility", "An insurance agent", "The director of a major company", "A government inspector"], "ans": 3, "ko": "화자는 누가 방문할 것이라고 말하는가?"}, {"n": 90, "q": "Where will the managerial meeting take place?", "opts": ["In the main lobby", "In the factory staff room", "In a conference room", "In the speaker's office"], "ans": 3, "ko": "관리자 회의는 어디에서 열릴 것인가?"}, {"n": 91, "q": "According to the speaker, what will be discussed during the meeting?", "opts": ["Details of an upcoming visit", "Upgrades to safety equipment", "New duties for company personnel", "Revised quotas for the factory"], "ans": 0, "ko": "화자에 따르면, 회의 중에 무슨 내용이 논의될 것인가?"}], "script": [{"sp": "M", "en": "May I have your attention, please? An inspector from the Federal Department of Safety will be visiting our plant next Friday, the 12th. I just want to remind you all of a few things. First, because the inspector will examine each work area, you all must ensure that our safety equipment is in good condition. Following this meeting, I will hand out lists of things to check. Please fill these out and hand them in to your supervisor by the end of the day. Also, there will be a short meeting at 3 o'clock for all departmental managers. Since the conference room has been reserved already, we'll gather in my office. At that time, we will go over the entire schedule of events for the day the inspector visits our facility. OK, that's all for now.", "ko": "모두 주목해 주시겠습니까? 다음 주 금요일인 12일에 연방 안전부의 조사관이 우리 공장을 방문할 것입니다. 저는 그저 여러분 모두에게 몇 가지 사항들을 상기시켜 드리고 싶습니다. 먼저, 조사관이 각 작업 구역을 검사할 것이므로, 여러분 모두는 반드시 우리의 안전 장비가 좋은 상태에 있도록 해야 합니다. 이 회의 이후에, 확인해야 할 것들의 목록을 나눠 드리겠습니다. 그것들을 기재해서 오늘까지 여러분의 관리자에게 제출해 주시기 바랍니다. 또한, 3시에 모든 부서장들을 대상으로 한 짧은 회의가 있을 것입니다. 회의실이 이미 예약되어 있기 때문에, 우리는 제 사무실에서 모일 것입니다. 그때, 우리는 조사관이 우리 시설을 방문하는 날의 전체 행사 일정을 다시 검토할 것입니다. 좋습니다, 지금은 이게 전부입니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test09_92-94.mp3", "qs": [{"n": 92, "q": "What is the speaker mainly discussing?", "opts": ["A news conference", "A product launch", "A potential contract", "A corporate merger"], "ans": 3, "ko": "화자는 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 93, "q": "What does the speaker mention about Hanaway and Glarris Incorporated?", "opts": ["It is developing a consumer product.", "It offers consulting services.", "It operates in Europe.", "It is relocating its main office."], "ans": 2, "ko": "화자는 Hanaway and Glarris사에 관해 무엇을 언급하는가?"}, {"n": 94, "q": "According to the speaker, what will happen over the next two months?", "opts": ["Some employees will be transferred overseas.", "A company will improve its internal communication.", "Consumers will fill out research questionnaires.", "Materials will be prepared for a trade fair."], "ans": 1, "ko": "화자에 따르면, 다음 두 달 동안 무슨 일이 일어날 것인가?"}], "script": [{"sp": "W", "en": "Today marks an important development for both Hanaway Industries and Glarris Technologies. Now that our two companies have combined to form Hanaway and Glarris Incorporated, we are the largest information technology firm in Europe. By consolidating our resources, we have positioned ourselves to serve clients more successfully than ever. This will surely be a benefit to our customers and the industry as a whole. However, we have a lot of work to do before we become fully operational. To that effect, employees from both of the formerly separate companies must continue to establish effective communication with each other in order to improve efficiency. That will be our primary focus over the next two months.", "ko": "오늘은 Hanaway Industries사와 Glarris Technologies사 모두에게 중요한 발전을 기념하는 날입니다. 우리 두 회사가 합병되어 Hanaway and Glarris사를 만들었기 때문에, 우리는 유럽에서 가장 큰 정보 기술 회사입니다. 우리의 자원들을 통합함으로써, 우리는 그 어느 때보다 더 성공적으로 고객들의 요구를 충족시킬 수 있는 자리에 섰습니다. 이는 틀림없이 우리의 고객들과 산업 전체에 이익이 될 것입니다. 하지만, 우리는 완전하게 기능을 다 하게 되기 전까지 해야 할 일이 많습니다. 그런 취지에서, 이전에 서로 다른 회사였던 양사의 직원들은 효율성을 높일 수 있도록 서로 간의 효과적인 의사소통을 계속해서 구축해야 합니다. 이는 다음 두 달 동안 우리의 주된 초점이 될 것입니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "호주식 발음", "audio": "Test09_95-97.mp3", "qs": [{"n": 95, "q": "What is the purpose of the message?", "opts": ["To check the status of a project", "To suggest a schedule change", "To confirm an office location", "To cancel an appointment"], "ans": 1, "ko": "메시지의 목적은 무엇인가?"}, {"n": 96, "q": "What does the speaker ask the listener to do?", "opts": ["Contact his assistant", "Make a payment", "Approve a plan", "Order some supplies"], "ans": 2, "ko": "화자는 청자에게 무엇을 하라고 요청하는가?"}, {"n": 97, "q": "Look at the graphic. Which quantity on the invoice has to be updated?", "opts": ["10", "7", "2", "5"], "ans": 0, "ko": "시각 자료를 보시오. 송장의 어느 수량이 업데이트되어야 하는가?"}], "script": [{"sp": "M", "en": "Hello, Mr. Meade. This is Matthew from Bellville Interiors. I want to let you know that we'll be able to put up the wallpaper in your new office next week on March 29 rather than April 3, as one of our current projects will end earlier than expected. You wanted us to start as soon as possible, so I assume this plan is acceptable, but . . . um, please call me back to let me know for sure. One more thing. I double-checked the measurements of your office, and it will actually take 11 rolls of wallpaper to cover the walls. I'll update the original invoice and send you a new copy this afternoon. The only change will be the additional charge of $38 . . . plus tax, of course.", "ko": "안녕하세요, Mr. Meade. 저는 Bellville 인테리어사의 Matthew입니다. 저희의 현재 프로젝트 중 하나가 예상보다 일찍 끝날 것이기 때문에, 4월 3일이 아닌 다음 주 3월 29일에 귀하의 새로운 사무실에 벽지를 바를 수 있을 것임을 알려드리고자 합니다. 고객님께서는 저희가 가능한 한 빨리 시작하기를 원하셨기 때문에, 이 계획이 받아들여질 것으로 생각합니다만… 음, 제게 다시 전화주셔서 확실히 알려주시기 바랍니다. 한 가지 더 있습니다. 제가 고객님의 사무실 치수를 다시 확인해 보았는데, 벽을 덮는 데에 실제로는 11롤의 벽지가 필요할 것입니다. 제가 원래의 송장을 업데이트하고 오늘 오후에 새로운 사본을 보내드리겠습니다. 유일한 변경은 추가 요금 38달러일 것입니다… 물론, 추가로 세금도요."}], "gimg": "hk2_t9_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "영국식 발음", "audio": "Test09_98-100.mp3", "qs": [{"n": 98, "q": "Who most likely are the listeners?", "opts": ["Financial advisors", "Marketing professionals", "Administrative staff", "Company shareholders"], "ans": 1, "ko": "청자들은 누구인 것 같은가?"}, {"n": 99, "q": "Look at the graphic. Which expense will most likely be reduced?", "opts": ["Media", "Printing", "Salaries", "Supplies"], "ans": 1, "ko": "시각 자료를 보시오. 어느 비용이 줄어들 것 같은가?"}, {"n": 100, "q": "What will happen next?", "opts": ["A report will be distributed.", "A presentation will be given.", "A task will be explained.", "A decision will be announced."], "ans": 0, "ko": "다음에 무슨 일이 일어날 것인가?"}], "script": [{"sp": "W", "en": "After reviewing last quarter's financial reports, the CEO has decided that we need to reduce expenditures across the board. He asked that all employees come up with ways to cut their department's expenses. So, it's our responsibility to reduce spending in the marketing department. This is a priority, so you should postpone your other projects if necessary. There isn't much we can do about the expense that accounts for the greatest share of our operating budget, but I guess we could try to reduce the next largest item by 20 percent. I have prepared an overview of our department's monthly expenditures to help you with this task. Um, I'll hand it out to everyone in a minute.", "ko": "지난 분기의 재무 보고서를 검토한 후, 최고 경영자는 우리가 전반적으로 지출을 줄여야 한다고 결정했습니다. 그는 전 직원이 그들 부서의 비용을 절감할 방안들을 제시할 것을 요청했습니다. 그러므로, 마케팅 부서 내의 지출을 줄이는 것이 우리의 책임입니다. 이것이 우선 사항이므로, 필요하다면 다른 프로젝트들을 미뤄야 할 것입니다. 우리 운영 예산의 가장 큰 비율을 차지하는 비용에 대해서는 할 수 있는 게 많지 않지만, 그 다음으로 큰 항목을 20퍼센트까지 줄이려고 노력해 볼 수 있을 것 같습니다. 이 업무에 대해 여러분에게 도움이 되도록 우리 부서의 월간 지출 개요를 준비했습니다. 음, 제가 곧 모두에게 그것을 나눠드리겠습니다."}], "gimg": "hk2_t9_g98.jpg"}]};
